import { Ask, Separator } from "@jpravetz/ask";

const ask = new Ask();

const { topping } = await ask.select({
  name: "topping",
  message: "Select a pizza topping:",
  choices: [
    { message: "Pepperoni", value: "pepperoni" },
    { message: "Mushrooms", value: "mushrooms" },
    new Separator(),
    { message: "Pineapple", value: "pineapple" },
 ],
} as const);

console.log(topping);
